// Test a pattern
const emailRegex = /^[\w.-]+@[\w.-]+\.[a-z]{2,}$/i;
console.log(emailRegex.test('user@example.com')); // true
console.log(emailRegex.test('not-an-email'));      // false

// Extract matches
const text = 'Call 0300-1234567 or 0800-9876543 for help';
const phones = text.match(/\d{4}-\d{7}/g);
console.log(phones); // ['0300-1234567', '0800-9876543']

// Replace
const censored = 'bad word here'.replace(/bad/i, '***');
console.log(censored); // '*** word here'

// Named capture groups
const dateStr = '2025-06-15';
const dateRegex = /(?<year>\d{4})-(?<month>\d{2})-(?<day>\d{2})/;
const { groups } = dateStr.match(dateRegex);
console.log(groups.year, groups.month, groups.day); // 2025 06 15
